import{_ as a,o as e,c as r,a7 as d}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Caro (血肉)","description":"","frontmatter":{},"headers":[],"relativePath":"en/realms/caro.md","filePath":"en/realms/caro.md","lastUpdated":1775394001000}'),o={name:"en/realms/caro.md"};function n(i,t,s,l,h,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="caro-血肉" tabindex="-1">Caro (血肉) <a class="header-anchor" href="#caro-血肉" aria-label="Permalink to &quot;Caro (血肉)&quot;">​</a></h1><p><span class="realm-badge realm-caro">Caro</span> is the realm of flesh and mutation. Caro Awakeners specialize in creating <strong>Embryo</strong> cards and consuming them for devastating burst effects. Currently ranked as an <strong>S-tier realm</strong> alongside Aequor.</p><h2 id="core-identity" tabindex="-1">Core Identity <a class="header-anchor" href="#core-identity" aria-label="Permalink to &quot;Core Identity&quot;">​</a></h2><p>Caro is a combo-oriented realm built around a two-step cycle: generate Embryo cards, then consume them for powerful effects. Mastering this cycle requires careful hand management and turn planning. It has the <strong>highest difficulty</strong> of all four realms to play optimally.</p><h2 id="key-mechanics" tabindex="-1">Key Mechanics <a class="header-anchor" href="#key-mechanics" aria-label="Permalink to &quot;Key Mechanics&quot;">​</a></h2><h3 id="realm-talent-embryo-system" tabindex="-1">Realm Talent: Embryo System <a class="header-anchor" href="#realm-talent-embryo-system" aria-label="Permalink to &quot;Realm Talent: Embryo System&quot;">​</a></h3><p>After activating the Caro realm talent, an Embryo gauge appears above the team. The gauge fills through Caro Awakener skills (Embryo Fusion). At 100%, an &quot;Embryo&quot; card is added to the player&#39;s hand.</p><h3 id="embryo-consumption-devour" tabindex="-1">Embryo Consumption (Devour) <a class="header-anchor" href="#embryo-consumption-devour" aria-label="Permalink to &quot;Embryo Consumption (Devour)&quot;">​</a></h3><p>While holding an Embryo card, Caro Awakeners can combine it with their Aliemus Burst to trigger a &quot;Devour&quot; effect, consuming the Embryo for massively enhanced results. Embryos accelerate team-wide Aliemus generation and amplify burst damage.</p><table tabindex="0"><thead><tr><th>Consumption Effect</th><th>Description</th></tr></thead><tbody><tr><td>Burst Damage</td><td>Deal massive damage scaling with Embryos consumed</td></tr><tr><td>Area Damage</td><td>Convert Embryos into AoE attacks</td></tr><tr><td>Healing</td><td>Consume Embryos to restore HP</td></tr><tr><td>Buffs</td><td>Gain stat boosts based on number of Embryos consumed</td></tr></tbody></table><h3 id="pure-caro-resonance" tabindex="-1">Pure Caro Resonance <a class="header-anchor" href="#pure-caro-resonance" aria-label="Permalink to &quot;Pure Caro Resonance&quot;">​</a></h3><p>In a pure Caro composition, special enhanced effects are triggered.</p><h3 id="embryo-management-tips" tabindex="-1">Embryo Management Tips <a class="header-anchor" href="#embryo-management-tips" aria-label="Permalink to &quot;Embryo Management Tips&quot;">​</a></h3><ul><li>At Realm Mastery 34+, you naturally gain +35 Embryo Fusion per turn</li><li>End each battle with one support&#39;s energy full and Embryo Fusion at 70-100%</li><li>Awakening priority: Aigis &gt; Rhea &gt; Uvhash &gt; Faint</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The key to Caro gameplay is timing. Spend 1-2 turns generating Embryos, then consume them all in a single devastating burst turn. Caro has the hardest learning curve -- it is difficult to manage HP and Embryo advantage during early progression.</p></div><h2 id="caro-awakeners" tabindex="-1">Caro Awakeners <a class="header-anchor" href="#caro-awakeners" aria-label="Permalink to &quot;Caro Awakeners&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Awakener</th><th>Role</th><th>Tier</th><th>Availability</th></tr></thead><tbody><tr><td>Agrippa</td><td>Defense</td><td>T2</td><td>Standard</td></tr><tr><td>Aigis</td><td>Support</td><td>—</td><td>Standard</td></tr><tr><td>Alice</td><td>Sub-Attack</td><td>T1</td><td>Standard</td></tr><tr><td>Doresain</td><td>Attack</td><td>—</td><td>Limited</td></tr><tr><td>Faint</td><td>Sub-Attack</td><td>T2</td><td>Standard</td></tr><tr><td>Helot</td><td>Attack</td><td>—</td><td>Limited</td></tr><tr><td>Leigh</td><td>Chorus</td><td>—</td><td>Standard</td></tr><tr><td>Rhea</td><td>Support</td><td>T0</td><td>Standard</td></tr><tr><td>Salvador</td><td>Defense</td><td>—</td><td>Standard</td></tr><tr><td>Shilo</td><td>Attack</td><td>T3</td><td>Standard</td></tr><tr><td>Sorel</td><td>Attack</td><td>T0</td><td>Limited</td></tr><tr><td>Thais</td><td>Support</td><td>—</td><td>Limited</td></tr><tr><td>Uvhash</td><td>Attack</td><td>T0</td><td>Standard</td></tr><tr><td>Xu</td><td>Chorus</td><td>—</td><td>Limited</td></tr></tbody></table><h2 id="team-building-with-caro" tabindex="-1">Team Building with Caro <a class="header-anchor" href="#team-building-with-caro" aria-label="Permalink to &quot;Team Building with Caro&quot;">​</a></h2><ul><li><strong>Uvhash Standard Flesh</strong> -- Uvhash + Rhea + Aigis + Faint: The standard Caro team. Rhea + Aigis are the irreplaceable &quot;core 2&quot; of Caro.</li><li><strong>Father (Salvador) Comp</strong> -- Salvador + Rhea + Aigis + 24/Ramona: Community-recognized Top 3 strongest lineup. Salvador + signature wheel pushed Caro to S-tier. Rhea copies Salvador&#39;s 2-cost card for HP cycling.</li><li><strong>#24 Flesh Variant</strong> -- 24 + Helot/Rhea + Aigis + Salvador: 24&#39;s Caro resonance converts AP cost into Embryo Fusion + Power bonus.</li></ul><h2 id="strengths-and-weaknesses" tabindex="-1">Strengths and Weaknesses <a class="header-anchor" href="#strengths-and-weaknesses" aria-label="Permalink to &quot;Strengths and Weaknesses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strengths</th><th>Weaknesses</th></tr></thead><tbody><tr><td>Highest burst damage potential in the game</td><td>Requires setup turns before burst</td></tr><tr><td>S-tier realm with Salvador comp</td><td>Hand management adds complexity</td></tr><tr><td>Strong HP cycling and sustain</td><td>Embryo generation can be inconsistent</td></tr><tr><td>Currently tied for strongest realm</td><td>Highest difficulty to play optimally</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Embryo cards cost Arithmetica to play. Factor in the cost of both generating and consuming Embryos when planning your Arithmetica budget for the turn.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Realms Overview</a></li><li><a href="./../cards/deckbuilding.html">Deckbuilding Guide</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li></ul>',24)])])}const g=a(o,[["render",n]]);export{u as __pageData,g as default};
